# third window frame page2
class forecast(tk.Frame): 
    def __init__(self, parent, controller):
        tk.Frame.__init__(self, parent,bg = "#0e100f")
        tk.Frame.__init__(self, parent,bg = "#0e100f")
        def click_1(event):
            self.notebook.select(0)

        def click_2(event):
            self.notebook.select(1)

        def click_3(event):
            self.notebook.select(2)

        def click_4(event):
            self.notebook.select(3)

        def click_5(event):
            self.notebook.select(4)

        #1
        x1 , y1 = 130 + 15,240 + 15
        x2 , y2 = 130 + 15,270 + 15
        x3 , y3 = 130 + 15,300 + 15
        x4 , y4 = 130 + 15,330 + 15
        x5 , y5 = 130 + 15,360 + 15
        x6 , y6 = 130 + 15,390 + 15
        
        #2
